# Create diagnostic setting to route audit logs to Log Analytics
$body = @{
    name = 'entra-audit-to-law'
    workspaceId = '/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.OperationalInsights/workspaces/<law>'
    logs = @(
        @{ category = 'AuditLogs'; enabled = $true; retentionPolicy = @{ days = 90; enabled = $true } }
        @{ category = 'SignInLogs'; enabled = $true; retentionPolicy = @{ days = 90; enabled = $true } }
        @{ category = 'RiskyUsers'; enabled = $true; retentionPolicy = @{ days = 90; enabled = $true } }
    )
} | ConvertTo-Json -Depth 10

$uri = 'https://management.azure.com/providers/microsoft.aadiam/diagnosticSettings/entra-audit-to-law?api-version=2017-04-01-preview'
Invoke-RestMethod -Uri $uri -Method Put -Body $body -ContentType 'application/json' -Headers @{Authorization="Bearer $token"}

# Route Entra audit logs to Log Analytics using azurerm provider
resource "azurerm_monitor_aad_diagnostic_setting" "entra_audit" {
  name                       = "entra-audit-to-law"
  log_analytics_workspace_id = azurerm_log_analytics_workspace.main.id

  enabled_log {
    category = "AuditLogs"
    retention_policy {
      enabled = true
      days    = 90
    }
  }

  enabled_log {
    category = "SignInLogs"
    retention_policy {
      enabled = true
      days    = 90
    }
  }

  enabled_log {
    category = "RiskyUsers"
    retention_policy {
      enabled = true
      days    = 90
    }
  }
}
